agent-browser eval "
const title = document.querySelector('.titleline a')?.textContent?.trim();
const scoreEl = document.querySelector('#score_47362613') || document.querySelector('.score');
const points = scoreEl?.textContent?.trim();
// Get comment count from subtext
const subtext = document.querySelector('.subtext');
const links = subtext?.querySelectorAll('a');
let commentCount = null;
if (links) {
  for (const link of links) {
    if (link.textContent.includes('comment')) {
      commentCount = link.textContent.trim();
      break;
    }
  }
}
JSON.stringify({title, points, commentCount});
"

agent-browser eval "
// Find all top-level comments (indent=0)
const allComments = document.querySelectorAll('.comment-tree .comtr');
const topLevel = [];

for (const c of allComments) {
  const indentEl = c.querySelector('.ind img');
  const indent = indentEl ? parseInt(indentEl.getAttribute('width')) : 0;
  if (indent === 0) {
    const author = c.querySelector('.hnuser')?.textContent?.trim();
    const id = c.id;
    topLevel.push({id, author});
  }
}

// Count direct replies for each top-level comment
// Direct replies = next comments until we hit another indent=0 comment
const allCommentsList = Array.from(allComments);
const results = [];

for (let i = 0; i < topLevel.length; i++) {
  const tlId = topLevel[i].id;
  const startIdx = allCommentsList.findIndex(c => c.id === tlId);
  let replyCount = 0;

  // Count next comments at indent=40 (direct replies, indent width 40 = 1 level deep)
  for (let j = startIdx + 1; j < allCommentsList.length; j++) {
    const nextC = allCommentsList[j];
    const indentEl = nextC.querySelector('.ind img');
    const indent = indentEl ? parseInt(indentEl.getAttribute('width')) : 0;
    if (indent === 0) break; // another top-level comment
    if (indent === 40) replyCount++; // direct reply (1 level deep)
  }

  results.push({id: tlId, author: topLevel[i].author, directReplies: replyCount});
}

results.sort((a, b) => b.directReplies - a.directReplies);
JSON.stringify(results.slice(0, 10));
"

